solutionFiles.content:
tasks = []

with open("tasks.txt", "r") as file:
    for line in file:
        task = line.strip()
        if task != "":
            tasks.append(task)

while True:
    print("Task Tracker")
    print("1. Add task")
    print("2. Show tasks")
    print("3. Delete task")
    print("4. Quit")

    choice = input()

    if choice == "1":
        task = input()
        tasks.append(task)
        with open("tasks.txt", "w") as file:
            for saved_task in tasks:
                file.write(saved_task + "\n")
        print("Task added")
    elif choice == "2":
        if len(tasks) == 0:
            print("No tasks yet")
        else:
            for index, task in enumerate(tasks, start=1):
                print(f"{index}. {task}")
    elif choice == "3":
        if len(tasks) == 0:
            print("No tasks to delete")
        else:
            number = int(input())
            if 1 <= number <= len(tasks):
                tasks.pop(number - 1)
                with open("tasks.txt", "w") as file:
                    for saved_task in tasks:
                        file.write(saved_task + "\n")
                print("Task deleted")
            else:
                print("Invalid task number")
    elif choice == "4":
        print("Goodbye!")
        break
    else:
        print("Invalid choice")

